

import { localCache } from "./localCache";

/**
 * 本地存储权限code的key
 */
const LOCAL_PERMISSION_CODE_KEY = Symbol('PERMISSION_CODE_DATA').toString();

/**
 * 根据传入的资源key，判断当前用户是否有这个资源的权限
 * @param permissionKey 权限key: developer按钮资源录入时填写的key
 */
export const hasAuth = (permissionKey: string):boolean => {
    const localPermissionCodeData = localCache.get(LOCAL_PERMISSION_CODE_KEY) || [];
    return localPermissionCodeData?.includes(permissionKey);
}